import { create } from 'zustand';

const INITIAL_HR_POOL = [
  { id: 'H1', name: '김안전', empType: 'REGULAR', licenseType: 'SAFETY', experience: 5, licenses: ['건설안전기사'], assignedSiteId: null },
  { id: 'H2', name: '이보건', empType: 'REGULAR', licenseType: 'HEALTH', experience: 3, licenses: ['간호사'], assignedSiteId: null },
  { id: 'H3', name: '박지도', empType: 'PROJECT', licenseType: 'SAFETY', experience: 10, licenses: ['산업안전지도사'], assignedSiteId: 'S1' },
  { id: 'H4', name: '최멀티', empType: 'REGULAR', licenseType: 'DUAL', experience: 8, licenses: ['안전기사', '위생기사'], assignedSiteId: null },
];

const INITIAL_SITES = [
  { id: 'S1', name: '서울 A건축현장', region: '서울권', type: 'ARCH', totalAmount: 1600, subAmt: 120, isSubProxy: true, endDate: '2027-12-31' },
  { id: 'S2', name: '경기 B토목현장', region: '경기권', type: 'CIVIL', totalAmount: 900, subAmt: 0, isSubProxy: false, endDate: '2026-10-31' },
];

export const useStore = create((set) => ({
  hrPool: INITIAL_HR_POOL,
  sites: INITIAL_SITES,
  
  assignStaff: (staffId, siteId) => set((state) => ({
    hrPool: state.hrPool.map((staff) => 
      staff.id === staffId ? { ...staff, assignedSiteId: siteId } : staff
    )
  })),

  unassignStaff: (staffId) => set((state) => ({
    hrPool: state.hrPool.map((staff) => 
      staff.id === staffId ? { ...staff, assignedSiteId: null } : staff
    )
  })),

  addStaff: (staff) => set((state) => ({
    hrPool: [...state.hrPool, { ...staff, id: `HR_${Date.now()}`, assignedSiteId: null }]
  })),

  addSite: (site) => set((state) => ({
    sites: [...state.sites, { ...site, id: `S_${Date.now()}` }]
  })),
}));
